contracts/CommitmentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./UserRegistry.sol";

contract CommitmentRegistry {
    // Structure pour stocker un commitment avec métadonnées
    struct Commitment {
        bytes32 value;           // Le hash (ex: Poseidon) des attributs
        uint256 timestamp;
        string metadataCID;      // Optionnel: description des attributs engagés (ex: "nom, date de naissance, nationalité")
    }

    // Chaque utilisateur ne peut avoir qu'un seul commitment actif (ou on peut en autoriser plusieurs)
    mapping(address => Commitment) public commitments;

    UserRegistry public userRegistry;

    event CommitmentSet(address indexed user, bytes32 commitmentValue, uint256 timestamp);
    event CommitmentUpdated(address indexed user, bytes32 oldValue, bytes32 newValue, uint256 timestamp);
    event CommitmentRevoked(address indexed user, uint256 timestamp);

    modifier onlyActiveUser(address _user) {
        require(userRegistry.isHolder(_user) || userRegistry.isIssuer(_user), "User not registered or not active");
        _;
    }

    constructor(address _userRegistry) {
        userRegistry = UserRegistry(_userRegistry);
    }

    // Enregistre ou met à jour le commitment de l'utilisateur (appelé par l'utilisateur lui-même)
    function setCommitment(bytes32 _commitment, string calldata _metadataCID) external onlyActiveUser(msg.sender) {
        require(_commitment != bytes32(0), "Commitment cannot be zero");

        Commitment storage existing = commitments[msg.sender];
        if (existing.value != bytes32(0)) {
            emit CommitmentUpdated(msg.sender, existing.value, _commitment, block.timestamp);
        } else {
            emit CommitmentSet(msg.sender, _commitment, block.timestamp);
        }

        commitments[msg.sender] = Commitment({
            value: _commitment,
            timestamp: block.timestamp,
            metadataCID: _metadataCID
        });
    }

    // Récupère le commitment actuel d'un utilisateur
    function getCommitment(address _user) external view returns (Commitment memory) {
        return commitments[_user];
    }

    // Optionnel: révoquer le commitment (l'utilisateur ne veut plus l'utiliser)
    function revokeCommitment() external onlyActiveUser(msg.sender) {
        require(commitments[msg.sender].value != bytes32(0), "No commitment to revoke");
        delete commitments[msg.sender];
        emit CommitmentRevoked(msg.sender, block.timestamp);
    }

    // Vérifie si un utilisateur a un commitment actif
    function hasCommitment(address _user) external view returns (bool) {
        return commitments[_user].value != bytes32(0);
    }
}

contracts/CredentialRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./UserRegistry.sol";

contract CredentialRegistry {
    enum Status { Active, Revoked, Expired }

    struct Credential {
        bytes32 docHash;        // SHA-256 du document (clair)
        string ipfsCID;         // CID IPFS du credential chiffré + signature
        address issuer;         // Adresse de l'émetteur (doit être enregistré avec rôle issuer)
        address holder;         // Adresse du détenteur (doit être enregistré)
        Status status;
        uint256 issuedAt;
        uint256 expiresAt;      // 0 = jamais
        string metadataCID;     // CID IPFS des métadonnées additionnelles
    }

    mapping(bytes32 => Credential) public credentials;
    mapping(address => bytes32[]) public issuerCredentials;
    mapping(address => bytes32[]) public holderCredentials;

    UserRegistry public userRegistry;
    uint256 public totalCredentials;

    event CredentialIssued(
        bytes32 indexed credentialId,
        address indexed issuer,
        address indexed holder,
        bytes32 docHash,
        string ipfsCID,
        uint256 issuedAt,
        uint256 expiresAt
    );
    event CredentialRevoked(bytes32 indexed credentialId, address indexed issuer, uint256 revokedAt);
    event CredentialStatusUpdated(bytes32 indexed credentialId, Status newStatus, uint256 updatedAt);

    modifier onlyIssuer(bytes32 _credentialId) {
        require(credentials[_credentialId].issuer == msg.sender, "Only issuer can perform");
        _;
    }

    modifier onlyActiveCredential(bytes32 _credentialId) {
        require(credentials[_credentialId].status == Status.Active, "Credential not active");
        _;
    }

    constructor(address _userRegistry) {
        userRegistry = UserRegistry(_userRegistry);
    }

    function issueCredential(
        bytes32 _docHash,
        string calldata _ipfsCID,
        address _holder,
        uint256 _expiresAt,
        string calldata _metadataCID
    ) external returns (bytes32) {
        require(userRegistry.isIssuer(msg.sender), "Caller is not an active issuer");
        require(userRegistry.isHolder(_holder), "Holder is not registered");
        require(_docHash != bytes32(0), "Doc hash required");
        require(bytes(_ipfsCID).length > 0, "IPFS CID required");

        bytes32 credentialId = keccak256(abi.encodePacked(msg.sender, _holder, _docHash, block.timestamp));
        require(credentials[credentialId].issuer == address(0), "Credential already exists");

        credentials[credentialId] = Credential({
            docHash: _docHash,
            ipfsCID: _ipfsCID,
            issuer: msg.sender,
            holder: _holder,
            status: Status.Active,
            issuedAt: block.timestamp,
            expiresAt: _expiresAt,
            metadataCID: _metadataCID
        });

        issuerCredentials[msg.sender].push(credentialId);
        holderCredentials[_holder].push(credentialId);
        totalCredentials++;

        emit CredentialIssued(credentialId, msg.sender, _holder, _docHash, _ipfsCID, block.timestamp, _expiresAt);
        return credentialId;
    }

    function revokeCredential(bytes32 _credentialId) external onlyIssuer(_credentialId) onlyActiveCredential(_credentialId) {
        credentials[_credentialId].status = Status.Revoked;
        emit CredentialRevoked(_credentialId, msg.sender, block.timestamp);
        emit CredentialStatusUpdated(_credentialId, Status.Revoked, block.timestamp);
    }

    function updateExpired(bytes32 _credentialId) external {
        Credential storage cred = credentials[_credentialId];
        if (cred.status == Status.Active && cred.expiresAt > 0 && cred.expiresAt <= block.timestamp) {
            cred.status = Status.Expired;
            emit CredentialStatusUpdated(_credentialId, Status.Expired, block.timestamp);
        }
    }

    function getCredential(bytes32 _credentialId) external view returns (Credential memory) {
        return credentials[_credentialId];
    }

    function isCredentialValid(bytes32 _credentialId) external view returns (bool) {
        Credential storage cred = credentials[_credentialId];
        if (cred.status != Status.Active) return false;
        if (cred.expiresAt > 0 && cred.expiresAt <= block.timestamp) return false;
        return true;
    }

    function getIssuerCredentials(address _issuer) external view returns (bytes32[] memory) {
        return issuerCredentials[_issuer];
    }

    function getHolderCredentials(address _holder) external view returns (bytes32[] memory) {
        return holderCredentials[_holder];
    }
}

contracts/UserRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract UserRegistry {
    // Rôles (bitmask)
    uint256 public constant ROLE_ISSUER = 1 << 0;  // 1
    uint256 public constant ROLE_HOLDER = 1 << 1; // 2
    uint256 public constant ROLE_VERIFIER = 1 << 2; // 4

    struct User {
        bytes mldsaPublicKey;    // ML-DSA-65 public key (obligatoire pour issuer, optionnel pour holder/verifier)
        bytes mlkemPublicKey;    // optionnel, pour chiffrement
        string metadataCID;      // CID IPFS du DID / profil
        uint256 roles;           // combinaison de ROLE_*
        bool active;
        uint256 registeredAt;
        uint256 updatedAt;
    }

    mapping(address => User) public users;
    address[] public userList;

    event UserRegistered(address indexed user, uint256 roles, uint256 timestamp);
    event UserUpdated(address indexed user, uint256 roles, uint256 timestamp);
    event UserRevoked(address indexed user, uint256 timestamp);

    modifier onlyActiveUser(address _user) {
        require(users[_user].active, "User not active");
        _;
    }

    modifier onlySelfOrAdmin(address _user) {
        require(msg.sender == _user || msg.sender == address(this), "Not authorized");
        _;
    }

    function registerUser(
        bytes calldata _mldsaPublicKey,
        bytes calldata _mlkemPublicKey,
        string calldata _metadataCID,
        uint256 _roles
    ) external {
        require(!users[msg.sender].active, "User already active");
        require(_roles != 0, "At least one role required");
        // Si le rôle émetteur est demandé, la clé ML-DSA est obligatoire
        if ((_roles & ROLE_ISSUER) != 0) {
            require(_mldsaPublicKey.length > 0, "ML-DSA key required for issuer");
        }

        users[msg.sender] = User({
            mldsaPublicKey: _mldsaPublicKey,
            mlkemPublicKey: _mlkemPublicKey,
            metadataCID: _metadataCID,
            roles: _roles,
            active: true,
            registeredAt: block.timestamp,
            updatedAt: block.timestamp
        });
        userList.push(msg.sender);
        emit UserRegistered(msg.sender, _roles, block.timestamp);
    }

    function updateUser(
        bytes calldata _mldsaPublicKey,
        bytes calldata _mlkemPublicKey,
        string calldata _metadataCID,
        uint256 _roles
    ) external onlyActiveUser(msg.sender) {
        require(_roles != 0, "At least one role required");
        if ((_roles & ROLE_ISSUER) != 0) {
            require(_mldsaPublicKey.length > 0, "ML-DSA key required for issuer");
        }
        User storage u = users[msg.sender];
        if (_mldsaPublicKey.length > 0) u.mldsaPublicKey = _mldsaPublicKey;
        if (_mlkemPublicKey.length > 0) u.mlkemPublicKey = _mlkemPublicKey;
        if (bytes(_metadataCID).length > 0) u.metadataCID = _metadataCID;
        u.roles = _roles;
        u.updatedAt = block.timestamp;
        emit UserUpdated(msg.sender, _roles, block.timestamp);
    }

    function revokeUser(address _user) external onlySelfOrAdmin(_user) {
        require(users[_user].active, "User already revoked");
        users[_user].active = false;
        users[_user].updatedAt = block.timestamp;
        emit UserRevoked(_user, block.timestamp);
    }

    function isIssuer(address _user) external view returns (bool) {
        return users[_user].active && ((users[_user].roles & ROLE_ISSUER) != 0);
    }

    function isHolder(address _user) external view returns (bool) {
        return users[_user].active && ((users[_user].roles & ROLE_HOLDER) != 0);
    }

    function isVerifier(address _user) external view returns (bool) {
        return users[_user].active && ((users[_user].roles & ROLE_VERIFIER) != 0);
    }

    function getUser(address _user) external view returns (User memory) {
        return users[_user];
    }

    function getAllUsers() external view returns (address[] memory) {
        return userList;
    }
}

contracts/VerificationOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract VerificationOracle {
    struct VerificationRequest {
        bytes32 credentialId;
        address requester;
        uint256 requestedAt;
        bool resolved;
        bool isValid;
        bytes32 proofHash;   // hash du résultat (signature + ZK proof)
        address resolver;
        uint256 resolvedAt;
    }

    mapping(uint256 => VerificationRequest) public requests;
    mapping(bytes32 => uint256[]) public credentialRequests;
    uint256 public totalRequests;

    address public oracle;
    address public pendingOracle;

    event VerificationRequested(uint256 indexed requestId, bytes32 indexed credentialId, address indexed requester, uint256 timestamp);
    event VerificationResolved(uint256 indexed requestId, bytes32 indexed credentialId, bool isValid, bytes32 proofHash, address resolver, uint256 timestamp);
    event OracleUpdated(address indexed oldOracle, address indexed newOracle);

    modifier onlyOracle() {
        require(msg.sender == oracle, "Only oracle can call");
        _;
    }

    constructor(address _oracle) {
        require(_oracle != address(0), "Oracle address required");
        oracle = _oracle;
    }

    function requestVerification(bytes32 _credentialId) external returns (uint256) {
        require(_credentialId != bytes32(0), "Invalid credentialId");
        uint256 requestId = totalRequests;
        requests[requestId] = VerificationRequest({
            credentialId: _credentialId,
            requester: msg.sender,
            requestedAt: block.timestamp,
            resolved: false,
            isValid: false,
            proofHash: bytes32(0),
            resolver: address(0),
            resolvedAt: 0
        });
        credentialRequests[_credentialId].push(requestId);
        totalRequests++;
        emit VerificationRequested(requestId, _credentialId, msg.sender, block.timestamp);
        return requestId;
    }

    function submitVerificationResult(
        uint256 _requestId,
        bool _isValid,
        bytes32 _proofHash
    ) external onlyOracle {
        require(_requestId < totalRequests, "Request does not exist");
        require(!requests[_requestId].resolved, "Already resolved");
        requests[_requestId].resolved = true;
        requests[_requestId].isValid = _isValid;
        requests[_requestId].proofHash = _proofHash;
        requests[_requestId].resolver = msg.sender;
        requests[_requestId].resolvedAt = block.timestamp;
        emit VerificationResolved(_requestId, requests[_requestId].credentialId, _isValid, _proofHash, msg.sender, block.timestamp);
    }

    function getVerificationStatus(uint256 _requestId) external view returns (bool resolved, bool isValid, uint256 requestedAt, uint256 resolvedAt) {
        VerificationRequest storage req = requests[_requestId];
        return (req.resolved, req.isValid, req.requestedAt, req.resolvedAt);
    }

    function getCredentialVerifications(bytes32 _credentialId) external view returns (uint256[] memory) {
        return credentialRequests[_credentialId];
    }

    function proposeNewOracle(address _newOracle) external onlyOracle {
        require(_newOracle != address(0), "Invalid address");
        pendingOracle = _newOracle;
    }

    function acceptOracle() external {
        require(msg.sender == pendingOracle, "Only pending oracle can accept");
        emit OracleUpdated(oracle, pendingOracle);
        oracle = pendingOracle;
        pendingOracle = address(0);
    }
}

